#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
struct node{
	vector<int> e;
	int f0,f1=1;
}v[maxn];
int n;
void t(int f,int x){
	for(auto i:v[x].e){
		if(i!=f){
			t(x,i);
			v[x].f0+=v[i].f1;
			v[x].f1+=min(v[i].f0,v[i].f1);
		}
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1,x,y;i<=n;i++){
		cin>>x>>y;
		for(int j=1,g;j<=y;j++){
			cin>>g;
			v[x+1].e.emplace_back(g+1);
			v[g+1].e.emplace_back(x+1);
		}
	}
	t(0,1);
	cout<<min(v[1].f0,v[1].f1);
	return 0;
}
